import java.util.HashSet;
import java.util.Set;

public class Solution {
    public int numBeautifulPartitions(String s, int k, int minLength) {
        final int MOD = 1000000007;
        Set<Character> primes = new HashSet<>();
        primes.add('2');
        primes.add('3');
        primes.add('5');
        primes.add('7');

        int n = s.length();
        int[][] dp = new int[n + 1][k + 1];
        dp[0][0] = 1;

        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= k; ++j) {
                for (int l = minLength; l <= i && i - l >= j - 1; ++l) {
                    if (primes.contains(s.charAt(i - l)) && !primes.contains(s.charAt(i - 1))) {
                        dp[i][j] += dp[i - l][j - 1];
                        if (dp[i][j] >= MOD) dp[i][j] -= MOD;
                    }
                }
            }
        }

        return dp[n][k];
    }
}
```

